const a = $input.first().json.result?.anomalies_found?.[0] || {};
const report = $input.first().json.result?.final_report || 'Revenue Guardian check completed.';
const lines = [
  '\ud83d\udea8 *Revenue Guardian Alert*',
  '',
  report,
  a.change_percent !== undefined ? `Change: ${a.change_percent}%` : '',
  a.severity ? `Severity: ${a.severity.toUpperCase()}` : '',
  a.latest_date ? `Date: ${a.latest_date}` : ''
].filter(Boolean);
return [{ json: { text: lines.join('\n') } }];
